import{c as t,Q as e,j as s,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Using GEPA to Hone Claude Haiku on GitHub Bug Fixes (+20%)","description":"","frontmatter":{"url":"https://tim.waldin.net/blog/2026-04-19-hone-haiku-20pp","title":"Using GEPA to Hone Claude Haiku on GitHub Bug Fixes (+20%)","date":"2026-04-19T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-19-hone-haiku-20pp.md","filePath":"research/ai-articles/scored/2026-04-19-hone-haiku-20pp.md","lastUpdated":1779894392000}'),i={name:"research/ai-articles/scored/2026-04-19-hone-haiku-20pp.md"};function r(o,a,l,p,d,c){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="using-gepa-to-hone-claude-haiku-on-github-bug-fixes-20" tabindex="-1">Using GEPA to Hone Claude Haiku on GitHub Bug Fixes (+20%) <a class="header-anchor" href="#using-gepa-to-hone-claude-haiku-on-github-bug-fixes-20" aria-label="Permalink to &quot;Using GEPA to Hone Claude Haiku on GitHub Bug Fixes (+20%)&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://tim.waldin.net/blog/2026-04-19-hone-haiku-20pp" target="_blank" rel="noreferrer">https://tim.waldin.net/blog/2026-04-19-hone-haiku-20pp</a><br><strong>作者</strong>：Timothy Waldin<br><strong>日期</strong>：2026-04-19<br><strong>收錄日期</strong>：2026-04-20</p><hr><h2 id="文章摘要" tabindex="-1">文章摘要 <a class="header-anchor" href="#文章摘要" aria-label="Permalink to &quot;文章摘要&quot;">​</a></h2><p>Claude Haiku 4.5 用 14 個字的 seed prompt 可解決 65% 的真實 GitHub bug。作者用 GEPA（來自 dspy 的 prompt 演化優化器）跑 7 小時、20 個 bug-fix 訓練挑戰，優化後的 prompt 讓同一個模型在 <strong>9 個未見過的 bug 上達到 85% 解決率</strong>，純靠 prompt prose 提升 20 個百分點。</p><h3 id="系統架構-三個現成工具組合" tabindex="-1">系統架構（三個現成工具組合） <a class="header-anchor" href="#系統架構-三個現成工具組合" aria-label="Permalink to &quot;系統架構（三個現成工具組合）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>元件</th><th>用途</th></tr></thead><tbody><tr><td><strong>GEPA</strong></td><td>Prompt 優化器（pareto 式 mutation + selection，來自 dspy）</td></tr><tr><td><strong>harness</strong></td><td>Python 函式庫，把 6 個 AI coding CLI（Claude Code、Codex、opencode、Gemini、Cursor、Aider）封裝成統一 API</td></tr><tr><td><strong>agentelo</strong></td><td>Leaderboard / 挑戰評分器，評分公式：<code>tests_fixed / tests_broken_before</code></td></tr><tr><td><strong>hone</strong></td><td>~300 行協調器，串起以上三者</td></tr></tbody></table><h3 id="訓練結果" tabindex="-1">訓練結果 <a class="header-anchor" href="#訓練結果" aria-label="Permalink to &quot;訓練結果&quot;">​</a></h3><p>20 個來自 5 個 repo（click/marshmallow/qs/jinja/koa）的真實 PR：</p><table tabindex="0"><thead><tr><th>iter</th><th>candidate</th><th>full valset (20)</th><th>delta</th></tr></thead><tbody><tr><td>0</td><td>seed（14 words）</td><td>0.5476</td><td>—</td></tr><tr><td>1</td><td>candidate 1（6-step v1）</td><td>0.8583</td><td>+0.3107</td></tr><tr><td>2</td><td>candidate 2（6-step v2）</td><td>0.9176</td><td>+0.3700</td></tr><tr><td>3</td><td>candidate 3（tied）</td><td>0.9176</td><td>+0.3700</td></tr></tbody></table><h3 id="holdout-結果-9-個未見-bug-×-3-次取樣" tabindex="-1">Holdout 結果（9 個未見 bug × 3 次取樣） <a class="header-anchor" href="#holdout-結果-9-個未見-bug-×-3-次取樣" aria-label="Permalink to &quot;Holdout 結果（9 個未見 bug × 3 次取樣）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>sample</th><th>seed</th><th>honed</th><th>delta</th></tr></thead><tbody><tr><td>mean</td><td>0.6496</td><td>0.8462</td><td><strong>+0.1966</strong></td></tr></tbody></table><p>requests 和 flask 完全不在訓練集，但同樣有改善——約一半的訓練提升泛化到測試集。</p><h3 id="gepa-發現的核心-failure-mode" tabindex="-1">GEPA 發現的核心 failure mode <a class="header-anchor" href="#gepa-發現的核心-failure-mode" aria-label="Permalink to &quot;GEPA 發現的核心 failure mode&quot;">​</a></h3><p>Haiku 修好第一個失敗測試後就宣告完成（premature victory）。優化後的 prompt 強調：</p><ul><li>讀 <strong>所有</strong> failing tests，不只第一個</li><li>Trace <strong>每個</strong> failure 的根因</li><li>同一邏輯錯誤出現多處 → 全部修正</li><li>持續迭代直到 <strong>每個</strong> 原本失敗的 test 都過</li></ul><h3 id="優化後的完整-prompt-candidate-2" tabindex="-1">優化後的完整 Prompt（Candidate 2） <a class="header-anchor" href="#優化後的完整-prompt-candidate-2" aria-label="Permalink to &quot;優化後的完整 Prompt（Candidate 2）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You are an AI coding agent fixing a bug in an open-source project.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Follow this process for every task:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Read ALL the failing tests first. Before touching any source code, read the</span></span>
<span class="line"><span>   relevant test files completely. Run the test suite and capture the full</span></span>
<span class="line"><span>   output — note every failing test case, not just the first one. Group the</span></span>
<span class="line"><span>   failures by type to understand the full scope of what needs to be fixed.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Find the root cause. Trace each failure to the specific line(s) responsible.</span></span>
<span class="line"><span>   Read the source code — not just the test file. If multiple test cases fail,</span></span>
<span class="line"><span>   check whether they share a single root cause or require separate fixes.</span></span>
<span class="line"><span>   Check git log or comments if the logic is unclear.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Fix the root cause, not the symptom. Make the minimal change that makes the</span></span>
<span class="line"><span>   failing tests pass without breaking existing tests. Do not add workarounds</span></span>
<span class="line"><span>   or special-case patches if the underlying logic is wrong. If the same</span></span>
<span class="line"><span>   logical error appears in multiple places in the source, fix all of them.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Handle edge cases. If the tests involve edge cases (empty strings,</span></span>
<span class="line"><span>   null/undefined, special characters, numeric boundaries, nested structures,</span></span>
<span class="line"><span>   encoding, array notation, option flags), make sure your fix handles all of</span></span>
<span class="line"><span>   them — not just the obvious case. For libraries with configurable behavior,</span></span>
<span class="line"><span>   check whether option or configuration values affect the code path you are</span></span>
<span class="line"><span>   fixing.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. Verify all tests pass. After editing, run the full test suite. If some</span></span>
<span class="line"><span>   previously failing tests still fail, do not stop — re-read those specific</span></span>
<span class="line"><span>   failing test cases, understand precisely what they expect, and revise your</span></span>
<span class="line"><span>   fix. Keep iterating until every originally-failing test passes and no</span></span>
<span class="line"><span>   regressions are introduced.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. Persist through partial fixes. If your fix makes some but not all tests</span></span>
<span class="line"><span>   pass, treat that as an incomplete fix. Re-read the remaining failures</span></span>
<span class="line"><span>   carefully, check if there is a second location in the source that needs the</span></span>
<span class="line"><span>   same or a related fix, and continue. Partial progress is not success.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Keep changes minimal and correct. Do not refactor unrelated code or add new</span></span>
<span class="line"><span>tests unless explicitly required.</span></span></code></pre></div><h3 id="goldilocks-band-條件" tabindex="-1">Goldilocks Band 條件 <a class="header-anchor" href="#goldilocks-band-條件" aria-label="Permalink to &quot;Goldilocks Band 條件&quot;">​</a></h3><p>GEPA 只在 seed solve rate <strong>0.5–0.7</strong> 的模型有效：</p><ul><li>太弱（Gemini 2.5 Flash，~0.2）→ 模型無法執行 6-step 方法論，即使 prompt 再好也沒用</li><li>已飽和（GPT-5.2/5.4-mini，~0.85+）→ seed prompt 已匹配模型內部行為，GEPA 無法改善</li></ul><p>Claude Haiku 4.5 恰好落在 0.65 seed solve rate，是理想的優化目標。</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>Candidate 2 prompt 可直接嵌入 implementer agent 或 autoresearch:fix，立即提升 bug fix 品質</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>GEPA 自動化 prompt 演化是新思路；具體 prompt 內容（ALL tests、persistence）對 workspace 是新增維度</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>嚴謹的 train/holdout split、3×27 次取樣、無迴歸、跨 repo 泛化</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>完整 prompt 內容、架構細節、failure mode 分析都完整揭露</td></tr><tr><td>E. 泛化性</td><td>7/10</td><td>跨 codebase 泛化驗證（flask/requests 不在訓練集）；Goldilocks 條件限制了 GEPA 本身的通用性</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.85/10</strong></td><td></td></tr></tbody></table><p><strong>整合決策</strong>：SKILL<br><strong>理由</strong>：核心價值是一個已驗證的靜態 system prompt，適合包成可隨時呼叫的 Skill；GEPA 本身需要 7 小時 + 20 個訓練挑戰，不適合日常使用，但 prompt 本身可以直接套用。<br><strong>整合位置</strong>：<code>.claude/skills/bugfix/</code> + 更新 <code>implementer</code> agent 預設行為<br><strong>整合狀態</strong>：✅ 已完成（見 <code>.claude/skills/bugfix/</code>）</p>`,26)])])}const g=t(i,[["render",r]]);export{u as __pageData,g as default};
